settings.liquid:
{%- assign p = all_products['ableton-master'] -%}
{%- if p -%}

  {%- assign v = p.selected_or_first_available_variant -%}

  {%- assign mo = nil -%}

  {%- if v and v.metafields.custom.buy_button.value != blank -%}
    {%- assign mo = v.metafields.custom.buy_button.value -%}
  {%- elsif p.metafields.custom.buy_button.value != blank -%}
    {%- assign mo = p.metafields.custom.buy_button.value -%}
  {%- endif -%}

  {%- if mo -%}
    {%- render 'meta-buy-button', mo: mo, force_label: 'Commencer la formation' -%}
  {%- else -%}
    <!-- buy_button introuvable (ni sur la variante, ni sur le produit) -->
  {%- endif -%}

{%- else -%}
  <!-- Produit introuvable -->
{%- endif -%}

{%- assign v = product.selected_or_first_available_variant -%}

<p class="heading" style="display:flex; gap:12px; align-items:baseline; font-size:clamp(24px, 5vw, 40px);">
  {%- if v.compare_at_price > v.price -%}
    <s style="color:#B87533; opacity:0.9;">
      {{ v.compare_at_price | money }}
    </s>
  {%- endif -%}
  <span>
    {{ v.price | money }}
  </span>
</p>

{%- assign v = product.selected_or_first_available_variant -%}

{%- if v.compare_at_price and v.compare_at_price > v.price -%}
  {%- assign savings_cents = v.compare_at_price | minus: v.price -%}
  <p class="sw-savings">
    {{ savings_cents | money_with_currency | replace: 'EUR', '' | strip }} euros d'économies
  </p>
{%- endif -%}

